edges=[('a','b'),('c','d'),('d','e')]
adj = defaultdict(set)
for u, v in edges:
    adj[u].add(v); adj[v].add(u)
seen, comps = set(), []
for start in sorted(adj):
    if start in seen:
        continue
    q, comp = [start], []
    seen.add(start)
    while q:
        n = q.pop()
        comp.append(n)
        for m in adj[n]:
            if m not in seen:
                seen.add(m); q.append(m)
    comps.append(sorted(comp))
