from collections import defaultdict, deque
adj = defaultdict(set)
for u, v in [('A','B'),('B','C'),('C','D')]:
    adj[u].add(v); adj[v].add(u)

def path(s, t):
    q = deque([(s, [s])])
    seen = {s}
    while q:
        n, p = q.popleft()
        if n == t:
            return p
        for m in sorted(adj[n]):
            if m not in seen:
                seen.add(m)
                q.append((m, p + [m]))
    return None
p = path('A', 'D')
print(p, len(p) - 1)

