from collections import defaultdict
edges=[('A','B'),('B','C'),('C','D')]
adj = defaultdict(set)
for u, v in edges:
    adj[u].add(v); adj[v].add(u)

def ego(seed, k):
    layer = {seed}
    seen = {seed}
    for _ in range(k):
        nxt = set()
        for n in layer:
            for m in adj[n]:
                if m not in seen:
                    nxt.add(m); seen.add(m)
        layer = nxt
    return sorted(seen)
print(ego('A', 1), ego('A', 2))

